import { Component } from '@angular/core';
import { ApiService } from '../../services/api.service';
import { AuthService } from '../../services/auth.service';
import { Router } from '@angular/router';

@Component({
  selector: 'app-auth',
  templateUrl: './auth.component.html'
})
export class AuthComponent {
  public isRegister = false;
  public model: any = {
    name: '',
    email: '',
    password: '',
    phoneNumber: '',
    age: 18,
    proof: ''
  };
  public errorMessage = '';
  public loading = false;

  constructor(private api: ApiService, private auth: AuthService, private router: Router) {}

  public toggleMode() {
    this.isRegister = !this.isRegister;
    this.errorMessage = '';
  }

  private extractError(err: any): string {
    if (!err.error) return err.statusText || 'An error occurred';
    if (typeof err.error === 'string') return err.error;
    if (Array.isArray(err.error)) return err.error.join(' ');
    if (err.error.message) return err.error.message;
    if (err.error.errors) {
      const msgs = Object.values(err.error.errors as Record<string, string[]>).flat();
      return msgs.join(' ');
    }
    return err.statusText || 'An error occurred';
  }

  public submit() {
    this.errorMessage = '';
    this.loading = true;
    if (this.isRegister) {
      this.api.register(this.model).subscribe({
        next: (result: any) => {
          this.auth.setSession(result.token, { name: result.userName, roles: result.roles });
          this.router.navigate(['/dashboard']);
        },
        error: err => { this.loading = false; this.errorMessage = this.extractError(err); }
      });
    } else {
      this.api.login(this.model).subscribe({
        next: (result: any) => {
          this.auth.setSession(result.token, { name: result.userName, roles: result.roles });
          this.router.navigate(['/dashboard']);
        },
        error: err => { this.loading = false; this.errorMessage = this.extractError(err); }
      });
    }
  }
}
<div class="card" style="max-width:420px;margin:2rem auto">
  <h2>{{ isRegister ? 'Create Account' : 'Login' }}</h2>
  <form (ngSubmit)="submit()" #authForm="ngForm">
    <div *ngIf="isRegister">
      <label>Full Name</label>
      <input [(ngModel)]="model.name" name="name" required placeholder="e.g. Rahul Kumar" />
      <label>Phone Number</label>
      <input [(ngModel)]="model.phoneNumber" name="phoneNumber" required placeholder="10-digit mobile number" />
      <label>Age</label>
      <input type="number" [(ngModel)]="model.age" name="age" required min="1" max="120" />
      <label>ID Proof (optional)</label>
      <input [(ngModel)]="model.proof" name="proof" placeholder="Aadhaar / PAN / Passport" />
    </div>
    <label>Email</label>
    <input type="email" [(ngModel)]="model.email" name="email" required placeholder="you@example.com" />
    <label>Password</label>
    <input type="password" [(ngModel)]="model.password" name="password" required placeholder="Min 6 chars, include A-Z, 0-9, symbol" />
    <p *ngIf="isRegister" style="font-size:0.78rem;color:#64748b;margin:0 0 0.75rem">
      Password must be at least 6 characters and contain uppercase, lowercase, digit and a special character (e.g. <strong>Test@1234</strong>).
    </p>
    <button type="submit" class="btn btn-primary btn-large" style="margin-top:8px" [disabled]="loading || authForm.invalid">
      {{ loading ? 'Please wait…' : (isRegister ? 'Sign Up' : 'Log In') }}
    </button>
  </form>
  <p *ngIf="errorMessage" style="color:#dc2626;margin-top:0.75rem">{{ errorMessage }}</p>
  <p style="margin-top:1rem">
    <a (click)="toggleMode()" style="cursor:pointer;text-decoration:underline;color:#d84e55">
      {{ isRegister ? 'Already have an account? Log In' : 'New here? Create an account' }}
    </a>
  </p>
</div>
